onClick:
{{
(() => {
  if (!Checkbox_Approve.isChecked) {
    return showAlert("Please confirm approval", "warning");
  }
  return InsertOrUpdateSignOff.run()
    .then(() => GetDepartmentSignOff.run())
    .then(() => GetNextDepartmentForPO.run())
    .then(() => {
      const nextDept = GetNextDepartmentForPO.data[0]?.Department;
      if (nextDept) {
        return storeValue("nextDepartment", nextDept)
          .then(() => GetNextDepartmentEmails.run())
          .then(() => SendNextDepartmentEmail.run());
      }
    })
    .then(() => {
      closeModal("Modal_ApproveDept");
      showAlert("Department approved", "success");
    })
    .catch(() => {
      showAlert("Approval failed", "error");
    });
})()
}}
